import { Copy, ExternalLink } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { useToast } from '@/hooks/use-toast';

interface BankTransferInstructionsProps {
  checkoutId: string;
  checkoutUrl: string;
}

const supportedBanks = ['BPI Online', 'BDO Online', 'UnionBank Online', 'LandBank Online', 'Metrobank Online'];

export default function BankTransferInstructions({
  checkoutId,
  checkoutUrl,
}: BankTransferInstructionsProps) {
  const { toast } = useToast();

  const handleCopy = async () => {
    await navigator.clipboard.writeText(checkoutId);
    toast({ title: 'Reference copied', description: 'Checkout reference copied to clipboard.' });
  };

  return (
    <Card className="border-primary/20 bg-primary/5">
      <CardContent className="p-4 space-y-3">
        <div className="flex items-center justify-between gap-3">
          <div>
            <p className="text-sm text-muted-foreground">Bank Transfer Reference</p>
            <p className="font-mono text-sm font-semibold text-foreground">{checkoutId}</p>
          </div>
          <Button variant="outline" size="sm" onClick={handleCopy} className="gap-2">
            <Copy className="h-4 w-4" />
            Copy
          </Button>
        </div>

        <div className="text-sm text-muted-foreground">
          <p className="font-medium text-foreground mb-1">Supported banks</p>
          <div className="flex flex-wrap gap-2">
            {supportedBanks.map((bank) => (
              <span key={bank} className="rounded-full bg-background px-3 py-1 text-xs border border-border">
                {bank}
              </span>
            ))}
          </div>
        </div>

        <Button
          className="w-full gap-2"
          onClick={() => window.open(checkoutUrl, '_blank', 'noopener,noreferrer')}
        >
          Continue to Bank Transfer
          <ExternalLink className="h-4 w-4" />
        </Button>
        <p className="text-xs text-muted-foreground">
          Complete payment in your bank’s portal. Your appointment will be confirmed once payment succeeds.
        </p>
      </CardContent>
    </Card>
  );
}
