import { useEffect } from 'react';
import { User, Phone, Mail, FileText, Users } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { useBookingStore } from '@/store/bookingStore';
import { useAuthStore } from '@/store';

// Mock family members
const mockFamilyMembers = [
  { id: 'fm-1', name: 'Juan Santos Jr.', relationship: 'Son', age: '12' },
  { id: 'fm-2', name: 'Maria Santos Sr.', relationship: 'Mother', age: '65' },
];

export default function PatientDetailsStep() {
  const { user } = useAuthStore();
  const {
    patientDetails,
    isExistingPatient,
    setPatientDetails,
    setIsExistingPatient,
  } = useBookingStore();

  // Pre-fill with logged-in user data if booking for self
  useEffect(() => {
    if (patientDetails.isForSelf && user) {
      setPatientDetails({
        fullName: user.name || '',
        email: user.email || '',
        contactNumber: user.phone || '',
      });
    }
  }, [patientDetails.isForSelf, user]);

  const handleInputChange = (field: string, value: string) => {
    setPatientDetails({ [field]: value });
  };

  const handleForSelfToggle = (isForSelf: boolean) => {
    setPatientDetails({ 
      isForSelf,
      ...(isForSelf ? {
        fullName: user?.name || '',
        email: user?.email || '',
        contactNumber: user?.phone || '',
        age: '',
        gender: '',
      } : {
        fullName: '',
        email: '',
        contactNumber: '',
        age: '',
        gender: '',
      })
    });
  };

  const handleFamilyMemberSelect = (memberId: string) => {
    const member = mockFamilyMembers.find(m => m.id === memberId);
    if (member) {
      setPatientDetails({
        fullName: member.name,
        age: member.age,
        familyMemberId: memberId,
      });
    }
  };

  return (
    <div className="space-y-6">
      {/* Patient Type Selection */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">
            <User className="h-5 w-5 text-primary" />
            Patient Type
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <RadioGroup
            value={isExistingPatient ? 'existing' : 'new'}
            onValueChange={(v) => setIsExistingPatient(v === 'existing')}
            className="flex gap-4"
          >
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="new" id="new" />
              <Label htmlFor="new" className="cursor-pointer">New Patient</Label>
            </div>
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="existing" id="existing" />
              <Label htmlFor="existing" className="cursor-pointer">Existing Patient</Label>
            </div>
          </RadioGroup>

          <div className="flex items-center justify-between p-4 rounded-lg bg-secondary/50">
            <div className="flex items-center gap-2">
              <Users className="h-5 w-5 text-muted-foreground" />
              <span className="text-sm font-medium">Booking for myself</span>
            </div>
            <Switch
              checked={patientDetails.isForSelf}
              onCheckedChange={handleForSelfToggle}
            />
          </div>

          {!patientDetails.isForSelf && mockFamilyMembers.length > 0 && (
            <div className="space-y-2">
              <Label>Select Family Member</Label>
              <Select onValueChange={handleFamilyMemberSelect}>
                <SelectTrigger>
                  <SelectValue placeholder="Choose a family member" />
                </SelectTrigger>
                <SelectContent>
                  {mockFamilyMembers.map((member) => (
                    <SelectItem key={member.id} value={member.id}>
                      {member.name} ({member.relationship})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Patient Information Form */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">
            <FileText className="h-5 w-5 text-primary" />
            Patient Information
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="fullName">
                Full Name <span className="text-destructive">*</span>
              </Label>
              <Input
                id="fullName"
                placeholder="Enter full name"
                value={patientDetails.fullName}
                onChange={(e) => handleInputChange('fullName', e.target.value)}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="age">
                Age <span className="text-destructive">*</span>
              </Label>
              <Input
                id="age"
                type="number"
                placeholder="Enter age"
                value={patientDetails.age}
                onChange={(e) => handleInputChange('age', e.target.value)}
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label>
              Gender <span className="text-destructive">*</span>
            </Label>
            <RadioGroup
              value={patientDetails.gender}
              onValueChange={(v) => handleInputChange('gender', v)}
              className="flex gap-4"
            >
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="male" id="male" />
                <Label htmlFor="male" className="cursor-pointer">Male</Label>
              </div>
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="female" id="female" />
                <Label htmlFor="female" className="cursor-pointer">Female</Label>
              </div>
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="other" id="other" />
                <Label htmlFor="other" className="cursor-pointer">Other</Label>
              </div>
            </RadioGroup>
          </div>

          <div className="grid sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="contactNumber">
                Contact Number <span className="text-destructive">*</span>
              </Label>
              <div className="relative">
                <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  id="contactNumber"
                  placeholder="+63 9XX XXX XXXX"
                  className="pl-10"
                  value={patientDetails.contactNumber}
                  onChange={(e) => handleInputChange('contactNumber', e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="email">
                Email Address <span className="text-destructive">*</span>
              </Label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  id="email"
                  type="email"
                  placeholder="email@example.com"
                  className="pl-10"
                  value={patientDetails.email}
                  onChange={(e) => handleInputChange('email', e.target.value)}
                />
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="symptoms">
              Reason for Consultation / Symptoms
            </Label>
            <Textarea
              id="symptoms"
              placeholder="Describe your symptoms or reason for the consultation..."
              rows={4}
              value={patientDetails.symptoms}
              onChange={(e) => handleInputChange('symptoms', e.target.value)}
            />
            <p className="text-xs text-muted-foreground">
              This helps the doctor prepare for your consultation
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Form Summary */}
      <Card className="border-primary/30 bg-primary/5">
        <CardContent className="p-4">
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <span className="text-destructive">*</span>
            <span>Required fields must be filled before continuing</span>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
